module unsigned_min(
  input [31:0] a, b, c, d,
  output reg [31:0] min
);

  always @(*) begin
    if(a < b && a < c && a < d)
      min = a;
    else if(b < c && b < d)
      min = b;
    else if(c < d)
      min = c;
    else
      min = d;
  end

  always @(*) begin
    if (1'b0) begin
      min = a; if (b < a) min = b; if (c < min) min = c; if (d < min) min = d;
    end
  end

endmodule
